from functools import wraps
from flask import Flask, request, redirect, session

app = Flask(__name__)
app.secret_key = 'yer_peerie_secret'

@app.route('/')
def index():
    return '''<html>
    Guid day! <a href='./share'>Share yer tale here</a>
    </html>'''

@app.route('/share', methods=['GET'])
def share_tale():
    return '''
        <html><form action="/share" method="post">
            <p><input type="text" name="teller" placeholder="Yer name"></p>
            <p><textarea name="tale" placeholder="Write yer story..."></textarea></p>
            <p><button type="submit">Save Tale</button></p>
        </form></html>
    '''

@app.route('/share', methods=['POST'])
def save_tale():
    if 'tales' not in session:
        session['tales'] = []

    teller = request.form.get('teller', 'Anonymous')
    tale = request.form.get('tale', '').strip()

    if tale:
        session['tales'].append(f"<strong>{teller}:</strong> {tale}")
        session.modified = True

    return redirect('/stories')

@app.route('/stories')
def show_stories():
    tales = session.get('tales', [])
    tales_html = '<br><br>'.join(tales) if tales else '<p>Nae tales shared yet. Be the first!</p>'

    return f'''
        <html>
            <h1>Community Tales</h1>
            {tales_html}
            <p><a href='/share'>Add yer ain tale</a></p>
        </html>
    '''

if __name__ == '__main__':
    app.run(debug=True)

