    wi open('bannocks.txt', 'r') as file:
        recipes = file.readlines()
    return [line.strip().split(',') for line in recipes if line.strip()]


@app.route('/bakery', methods=['POST'])
def mak_bannock():
    '''
    Get the chosed bannock name frae the request.
    Load aa the bannock recipes frae the file an find the richt yin.
    Show the bannock recipe wi ingredients an bakin instructions.
    '''
    chosed_bannock = request.form.get('bannock_name')
    recipes = load_bannocks()
    selected_recipe = next((recipe for recipe in recipes if recipe[0] == chosed_bannock), None)

    if selected_recipe:
        return render_template('bannock_recipe.html', name=selected_recipe[0], ingredients=selected_recipe[1], instructions=selected_recipe[2])
    return "Bannock no fund", 404

