    Gie back a bonny hash o da text an da saut, tae keep it safe frae pryin een.
    '''
    return hashlib.sha256((o_text + o_saut).encode()).hexdigest()

def mak_a_checksum(o_file: str):
    '''
    Gie a checksum o a file tae see if it's aye the same.
    '''
    wi hashlib.sha256() as hasher:
        wi open(o_file, 'rb') as f:
            while chunk := f.read(4096):
                hasher.update(chunk)
        return hasher.hexdigest()

