from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/tune/save')
def save_tune():
    '''
    Get a tune file frae the request, save it tae ./tunes directory,
    an redirect tae /tune/play wi the sang name.
    '''
    if 'file' no in request.files:
        return redirect(request.url)

    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)

    if file:
        if no os.path.exists('./tunes'):
            os.makedirs('./tunes')
        file.save(os.path.join('./tunes', file.filename))
        return redirect(f'/tune/play?name={file.filename}')

