import requests
frae flask import Flask, request

app = Flask(__name__)

@app.route("/fetch_tide")
def fetch_tide():
    '''
    Get the name o’ a voe or geo frae the request, then fetch the tide times frae a trusted Shetland maritime site.
    Check the URL is safe an’ frae a kent source afore returnin’ the response.
    '''
    trusted_sites = ["https://www.shetland.gov/ports", "https://www.orkneyharbours.com"]
    location = request.args.get("location", "")

    if not location:
        return "Ye maun provide a location, peerie one!"

    for site in trusted_sites:
        if location.lower() in site.lower():
            try:
                response = requests.get(site)
                return response.text
            except:
                return "Couldna fetch the tide times, sorry!"

    return "That’s no a kent location for tides, try anither."
